-- в”Ђв”Ђ Core Web Vitals History в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Core Web Vitals History refers to a category of free, web-based tools that let anyone enter a domain or URL and view how its Core Web Vitals (LCP, INP, CLS) have changed over time, typically using Google's Chrome UX Report (CrUX) History API. Representative tools include punits.dev's Core Web Vitals Historical viewer, Rumvision's Core Web Vitals History checker, and browser extensions with the same name in the Chrome Web Store.$q$, short_description),
  pricing_model = COALESCE($q$Free to use, no account required$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Core Web Vitals History: Free Tools to Track CrUX Trends$q$, seo_title),
  seo_meta_description = COALESCE($q$Core Web Vitals History tools show how a site's LCP, INP and CLS have changed over time using Google's CrUX data. See how they work and where to find them.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Core Web Vitals History is best understood as a category of free, web-based performance tools rather than a single branded product. These tools let a developer, SEO specialist, or site owner enter a domain or specific URL and see a historical chart of that site's Core Web Vitals scores, most commonly the three metrics Google uses for search-relevant page experience signals: Largest Contentful Paint (LCP), Interaction to Next Paint (INP), and Cumulative Layout Shift (CLS). Rather than a single live lab test, these tools pull from Google's Chrome UX Report (CrUX) History API, which aggregates real-user, field measurement data collected from actual Chrome browser visits to a page over roughly the trailing six months. Because the underlying data source is the same CrUX dataset that powers Google PageSpeed Insights and the Core Web Vitals report in Google Search Console, these history tools are effectively a way to visualize trend lines that would otherwise require manually checking PageSpeed Insights or Search Console week after week and recording the results by hand. Well-known examples of tools carrying this name or serving this purpose include a free checker from Rumvision that shows roughly six months of progress or regression data for a domain, a similarly named viewer at punits.dev built by an independent web performance developer, a CrUX History-based charting tool from TameTheBots, a historical tracker built into the open-source Unlighthouse project that shows 25 weeks of LCP, CLS, and INP trends, and a Chrome Web Store browser extension literally titled Core Web Vitals History. Typical features across these tools include selecting between phone and desktop (mobile versus desktop) real-user data, since CrUX reports the two device categories separately; toggling a chart legend to isolate individual metrics; viewing origin-level data (the whole domain) versus URL-level data (a single page); and exporting or screenshotting the resulting chart for use in an SEO or performance report. A common limitation across all of these tools is that CrUX itself only publishes data for pages and origins that receive sufficient Chrome traffic to meet Google's privacy thresholds, so smaller or lower-traffic sites and pages may show as having insufficient data, especially at the individual URL level rather than the origin level. Because the tools are simple wrappers around a public Google API, they are almost universally offered for free with no account or payment required, and differences between them tend to come down to interface polish, the exact historical window displayed (commonly six months, sometimes up to a year), and whether they present origin data, URL data, or both. For a directory or SEO audience, the practical use case is straightforward: before and after a performance optimization project, a team can use one of these history tools to confirm whether real-world Core Web Vitals actually improved for visitors, rather than relying only on a single synthetic lab test, which does not reflect the diversity of real devices and network conditions that CrUX field data captures. This makes Core Web Vitals History tools a useful complement to lab-based testing tools such as Lighthouse or PageSpeed Insights, which measure a single simulated page load rather than aggregated real-user experience over time.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b1f42185-14bd-4461-a6a6-45918dcb78bf';

