-- в”Ђв”Ђ Corgea в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Corgea is an AI-powered application security platform that scans source code, dependencies, containers, and infrastructure-as-code to find vulnerabilities and automatically generates fixable code patches. Founded in 2023 and based in San Francisco, it is backed by Y Combinator and positions itself as an AI-native alternative to traditional static application security testing (SAST) tools.$q$, short_description),
  pricing_model = COALESCE($q$Per-developer monthly subscription with a free tier and a custom Enterprise plan$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans start at 39 USD per developer per month)$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Approximately 6 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Corgea Review 2026: AI AppSec Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Corgea is an AI-native application security platform that finds and auto-fixes vulnerabilities. Compare 2026 pricing, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Corgea is an AI-powered application security (AppSec) platform that scans source code, open-source dependencies, containers, and infrastructure-as-code configurations to detect vulnerabilities and then uses AI agents to generate safe, ready-to-apply code fixes. The company was founded in 2023, is headquartered in San Francisco, California, and is backed by Y Combinator; public reporting places its team at roughly six employees as of research in 2026, making it a small, focused startup rather than a large incumbent security vendor. Corgea markets itself as an AI-native alternative to traditional static application security testing (SAST) tools, arguing that legacy SAST products generate large volumes of findings that developers do not have time to triage or fix manually, and that fixing a single vulnerability conventionally costs somewhere between 400 and 4,000 US dollars in developer time. Corgea's core pitch is that its AI agents can validate which findings are real (reducing false positives), triage them by severity and exploitability, and then draft the actual code fix inside the developer's existing workflow, cutting remediation time and cost significantly compared to manual fixing. The platform integrates with GitHub, GitLab, Azure DevOps, and Bitbucket, and can run as scheduled repository scans or as pull-request scans that block or flag risky changes before merge. Beyond classic SAST-style pattern scanning, Corgea also covers logic and authentication/authorization vulnerability detection, software composition analysis (dependency scanning) for vulnerable open-source packages, secrets detection for accidentally committed credentials, container image scanning, and infrastructure-as-code scanning for cloud misconfigurations. Corgea's pricing is structured around four tiers. The Free plan supports a team of up to two members, up to ten repositories, and up to ten pull-request scans per month, and includes the core AI SAST engine plus logic/auth scanning, dependency scanning, secrets detection, container scanning, and infrastructure-as-code scanning, with community forum support. The Growth plan costs 39 US dollars per developer per month with a minimum of five developers, raises the repository limit to 100 with unlimited PR scans, and adds full pull-request scanning, a code-quality layer, the Corgea Agent for automated fix generation, a Jira integration, software license enforcement, and up to 50 AI-generated auto-fixes. The Scale plan, described by Corgea as its most popular tier, costs 49 US dollars per developer per month with a minimum of 20 developers, raises the repository limit to 200, and adds custom and blocking rules, reporting and analytics dashboards, team management controls, APIs and webhooks, and up to 200 auto-fixes. The Enterprise plan is custom-priced, removes team and repository limits, and adds SSO and SCIM provisioning, single-tenant deployment options, formal SLA management, audit logging, and premium support. All paid tiers support both monthly and annual billing. Customer references include Epilot, a European utilities and energy software platform, which has publicly described rolling out Corgea's native GitLab integration to its engineering team in under a week, without the enterprise-only pricing or added CI complexity it experienced with a prior AppSec vendor. Corgea is best suited for engineering and security teams that want vulnerability findings paired directly with an actionable, AI-drafted fix rather than a raw list of issues to investigate manually, particularly smaller and mid-sized engineering organizations that lack a dedicated large application security team.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '24680a77-6673-4532-875d-be234e171239';

