-- в”Ђв”Ђ Country-State-City Microservice API в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Country-State-City Microservice API refers to open-source and free-tier REST and GraphQL APIs that provide hierarchical geographic data, countries, their states or provinces, and their cities, for use in address forms, location pickers, and geographic autocomplete features. The category includes hosted services such as countrystatecity.in and open-source datasets and packages such as the widely used countries-states-cities-database project.$q$, short_description),
  pricing_model = COALESCE($q$Free tier available on hosted services; underlying open-source datasets are free to self-host under permissive licenses$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Open-source community project$q$, company_size),
  headquarters = COALESCE($q$Not applicable (open-source project; primary services are maintainer-run rather than corporate)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Country State City API: Free Geographic Data for Developers$q$, seo_title),
  seo_meta_description = COALESCE($q$Country State City Microservice API provides free country, state and city data via REST or GraphQL for address forms and location pickers. See features and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Country-State-City Microservice API describes a category of open-source and free-tier services that give developers structured, hierarchical geographic data, countries, their states or provinces, and their cities, for use in address forms, shipping calculators, location-based autocomplete fields, and similar geographic UI components. Rather than a single company-owned product, this space is populated by a mix of hosted APIs and open-source datasets that developers can self-host as a lightweight microservice. The best-known hosted option, countrystatecity.in, describes itself as covering more than 250 countries, more than 5,300 states, and more than 153,800 cities, delivered through both REST and GraphQL endpoints with sub-200ms response times and a stated 99.9 percent uptime target. The service supports exporting data in CSV, JSON, or SQL formats, offers a free tier to start building, and reports being used by more than 50,000 developers with over 5.1 billion cumulative API requests processed. Its underlying data is described as ODbL-1.0 licensed for the core geographic database, with an MIT license applied to its accompanying software packages, and the dataset is also distributed via NPM, PyPI, and a command-line interface for teams that prefer to self-host rather than call a hosted API. On the open-source side, the most widely referenced underlying dataset in this category is the countries-states-cities-database project, maintained on GitHub, which compiles country, state, and city records into JSON, SQL, PostgreSQL, SQL Server, MongoDB, SQLite, XML, YAML, and CSV formats, including ISO2 and ISO3 country codes, country calling codes, capitals, native language names, and time zone information for countries. Because this dataset is open source, multiple independent developers have built their own microservice wrappers and APIs on top of it or similar datasets, including Laravel-based REST APIs, autocomplete-focused services, and, more recently, packages that ship as both an NPM library and a Model Context Protocol (MCP) server so that AI coding assistants and agents can query geographic data directly. Typical features across implementations in this category include full country lists with ISO codes, states or provinces nested under each country, cities nested under each state, search and autocomplete endpoints, filtering by country or state, and multiple export or delivery formats. Because much of the underlying data is community-maintained and periodically synced from public sources, hosted services in this category commonly describe their processes as involving community-driven updates, automated syncing, and real-time data validation, though the precision and completeness of city-level data can vary meaningfully by country, particularly for smaller administrative divisions or less-documented regions. For a directory or SEO context, the practical appeal of tools in this category is that they let developers avoid manually maintaining their own country, state, and city reference tables, a common but tedious requirement for e-commerce checkout flows, user registration forms, shipping and tax calculators, and any application that needs structured, hierarchical location data without building and updating that dataset in-house. Because most implementations offer either a genuinely free tier or a fully open-source, self-hostable dataset, the barrier to adoption is low, and teams often choose between a hosted API for convenience or a self-hosted open-source dataset for full control over data freshness, licensing, and infrastructure.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '665d4b24-214c-42c9-8e28-6289920470fa';

